1: /// A simple string tokenizer that splits input by delimiter,
2: /// respecting quoted strings.
3: 
4: pub struct StringTokenizer {
5:     delimiter: char,
6:     quote_char: char,
7: }
8: 
9: impl StringTokenizer {
10:     pub fn new(delimiter: char, quote_char: char) -> Self {
11:         Self { delimiter, quote_char }
12:     }
13: 
14:     pub fn tokenize(&self, input: &str) -> Vec<String> {
15:         let mut tokens = Vec::new();
16:         let mut current = String::new();
17:         let mut in_quotes = false;
18: 
19:         for ch in input.chars() {
20:             if ch == self.quote_char {
21:                 in_quotes = !in_quotes;
22:             } else if ch == self.delimiter && !in_quotes {
23:                 tokens.push(current.clone());
24:                 current.clear();
25:             } else {
26:                 current.push(ch);
27:             }
28:         }
29: 
30:         if !current.is_empty() {
31:             tokens.push(current);
32:         }
33: 
34:         tokens
35:     }
36: }

