#[cfg(test)]
mod tests {
    use super::*;

    fn csv() -> StringTokenizer {
        StringTokenizer::new(',', '"')
    }

    #[test]
    fn test_basic_split() {
        let tokens = csv().tokenize("a,b,c");
        assert_eq!(tokens, vec!["a", "b", "c"]);
    }

    #[test]
    fn test_empty_input() {
        let tokens = csv().tokenize("");
        assert!(tokens.is_empty());
    }

    #[test]
    fn test_single_token() {
        let tokens = csv().tokenize("hello");
        assert_eq!(tokens, vec!["hello"]);
    }

    #[test]
    fn test_consecutive_delimiters() {
        let tokens = csv().tokenize("a,,b");
        assert_eq!(tokens, vec!["a", "", "b"]);
    }

    #[test]
    fn test_quoted_string_with_delimiter() {
        let tokens = csv().tokenize("name,\"doe, john\",age");
        assert_eq!(tokens, vec!["name", "doe, john", "age"]);
    }

    #[test]
    fn test_trailing_delimiter() {
        // Note: trailing delimiter does NOT produce an empty final token
        // because the code only pushes if current is non-empty
        let tokens = csv().tokenize("a,b,");
        assert_eq!(tokens, vec!["a", "b"]);
    }

    #[test]
    fn test_leading_delimiter() {
        let tokens = csv().tokenize(",a,b");
        assert_eq!(tokens, vec!["", "a", "b"]);
    }

    #[test]
    fn test_only_delimiters() {
        let tokens = csv().tokenize(",,");
        assert_eq!(tokens, vec!["", ""]);
    }
}
